Part.Source:
&FilBasImp = RetornaFilialBaseImposto.Udp(&EmpCod, &FilCodFat)
&HojeData = serverdate()

For Each Order EmpCod, FilCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCodFat

	&FilCidCod = FilCidCod
	&FilCidNom = FilCidNom
	&FilCidUfeIbge = FilCidUfeIbge 
	&FilCidUfeCod = FilCidUfeCod
	&FilCep = FilCep

	Exit
EndFor

For Each Order EmpCod, LctCod
	Where EmpCod = &EmpCod
	Where LctCod = &LctCod
	&LctAtuSal = LctAtuSal
	Exit
EndFor


If &NfeCod = 0
	&NfeCod = UltimoCodigoEmpresa.Udp(domParCod.NOTAFISCAL, &EmpCod, &FilCodFat)

	//FIZ PEGAR NUMERO SOMENTE QUANDO TRANSMITIR - JDF., QUANDO VEM DE PEDIDOS JA PEGA O NUMERO EM OUTRO PROCEDIMENTO
	//&NfeNum = UltimoCodigoEmpresa.Udp(domParCod.NOTA65NUM, &EmpCod,  &FilCodFat)
	//RetornaSerieNF.Call(domParCod.NOTAFISCAL65_SERIE, &EmpCod, &FilCodFat, &NfeSer)

	New
		EmpCod = &EmpCod
		FilCod = &FilCodFat
		NfeCod = &NfeCod
		NfeFilCod = 0
		NfePedCod = 0
		NfeNum = &NfeNum
		NfeSer = &NfeSer
		NfeSts = Status_NFe.Digitando
