		//NfeProTaxMvaSt = tmpNfeProTaxMvaSt

		NfeDadManAdi = &NfeDadAdi
		NfeDadAdi = ''

		&TotLin  =  GxMlines(&NfeDadAdi, 100)
		&NumLin  =  1
		Do While &NumLin <= &TotLin
			NfeDadAdi = NfeDadAdi.Trim() + ' ' +GxGetMLi(&NfeDadAdi, &NumLin, 100)
			&NumLin += 1
		EndDo

		&TotLin  =  GxMlines(&tmpManNfeDadAdi, 100)
		&NumLin  =  1
		Do While &NumLin <= &TotLin
			NfeDadAdi = NfeDadAdi.Trim() + ' ' +GxGetMLi(&tmpManNfeDadAdi, &NumLin, 100)
			&NumLin += 1
		EndDo

		NfeQtdVol = 0 //&NfeQtdVol
		NfeEspVol = '' //&NfeEspVol

		NfeVlrTotPdg = 0
		NfeNroVol = ''
		NfeMarVol = ''
		NfeMotNom = ''
		NfeTraPlaCod = ''
		NfeTraPlaUF = ''

		NfePesLiq = 0 //&NfePesLiq
		NfePesBrt = 0 //&NfePesBrt

		NfeEmiGnre = Status_SimNao.Nao

		//NfsEstExp = &NfsEstExp	
	EndNew
