//		NfeTraTipPes =  TipoPessoa.FISICA // PedTraRedTipPes		

//		NfeChv = '' //CHAVE DA NFE

//		NfeVlrTotPro = 0 //&NfeVlrTotPro
//		NfeVlrTotFrt = 0 //&NfeVlrTotFrt
//		NfeVlrTotIpi = 0 //&NfeVlrTotIpi
