		&TotLin  =  GxMlines(&NfeDadAdi, 100)
		&NumLin  =  1
		Do While &NumLin <= &TotLin
			NfeDadAdi = NfeDadAdi.Trim() + ' ' +GxGetMLi(&NfeDadAdi, &NumLin, 100)
