Commit

parm(in:&EmpCod, in:&FilCodFat, in:&auxNfeNum, in:&NfeDtaEms, in:&NfeHorEms, in:&auxNfeSer, in:&NfeFin, in:&LctCod, in:&NfeCliEml, in:&NfeCliCod,
	in:&NfeCliRaz, in:&NfeCliTipPes, in:&NfeCliCpf, in:&NfeCliCnpj, in:&NfeDadAdi, in:&tmpManNfeDadAdi, 

